// ========================
// Utilitários
// ========================

function montarMensagem(template, params) {
  if (!template) return "";

  let msg = template;

  // Garante que params seja um array, mesmo que venha nulo
  const safeParams = Array.isArray(params) ? params : [];

  safeParams.forEach((valor, index) => {
    // Substitui {{1}}, {{2}}, etc.
    const placeholder = new RegExp(`{{\\s*${index + 1}\\s*}}`, "g");
    msg = msg.replace(placeholder, valor ?? "");
  });

  return msg;
}

function normalizeTelefone(raw) {
  if (raw == null) return "";
  let d = String(raw).replace(/\D/g, "").replace(/^0+/, "");
  return d ? (d.startsWith("55") ? d : "55" + d) : "";
}

// ========================
// Execução principal
// ========================

return items.map((item) => {
  const json = item.json;

  // 1. Mapeamento de Campos (Compatível com o output do passo anterior)
  // Tenta pegar 'message_template' (passo anterior) ou 'mensagem'
  const mensagemTemplate = json.message_template || json.mensagem || "";

  const nome = json.nome_participante || json.nome || "";
  const telefone = normalizeTelefone(json.phone || json.telefone);
  const template_name = json.meta_template_name || json.template_name || "";
  const participant_id = json.participant_id;
  const status = json.status || "pending";

  // 2. Tratamento de Parâmetros
  // Aceita tanto o Array 'parameters' (do código anterior) quanto chaves soltas 'param_x'
  let params = [];

  if (Array.isArray(json.parameters)) {
    params = json.parameters;
  } else {
    // Fallback para buscar param_0, param_1, etc.
    Object.keys(json).forEach((key) => {
      if (key.startsWith("param_")) {
        const index = Number(key.replace("param_", ""));
        params[index] = json[key];
      }
    });
  }

  // 3. Tratamento de Mídia (Sem download/Base64)
  // Pega 'image_url' (do código anterior) ou 'midia_url'
  const media_url = (json.image_url || json.midia_url || "").toString().trim();

  // Define o tipo. Se tiver url e for video no header ou template, assume video.
  // Caso contrário, se tiver url, assume imagem.
  let media_type = (json.media_type || "").toLowerCase();

  // Lógica simples de detecção se não vier explícito
  if (media_url && !media_type) {
      if (media_url.endsWith('.mp4')) {
          media_type = 'video';
      } else {
          media_type = 'image';
      }
  }

  const hasMedia = !!media_url && (media_type === 'image' || media_type === 'video');
  const isTextOnly = !hasMedia;

  // 4. Montagem da Mensagem Final (Preview para log/debug)
  const mensagem_completa = montarMensagem(mensagemTemplate, params);

  // ========================
  // Retorno
  // ========================
  return {
    json: {
      participant_id,
      telefone,
      nome,
      status,
      template_name,

      // Mensagem montada (texto com variáveis substituídas)
      mensagem_completa,

      // Parâmetros originais (importante para o nó do WhatsApp Cloud API)
      parameters: params,

      // Flags e Mídia
      hasMedia,
      isTextOnly,
      media_type: hasMedia ? media_type : null,
      media_url:  hasMedia ? media_url  : null,

      // Mantém compatibilidade caso precise de requires_image
      requires_image: json.requires_image || false
    }
  };
});

const items = $input.all().map(i => i.json);

// 1. Identifica os objetos corretamente baseados no JSON de Input
const template = items.find(i => i.message_template && Array.isArray(i.variables));
const event = items.find(i => i.nome_evento && i.data_hora_inicio); 

// 2. Filtra APENAS os participantes reais
const participants = items.filter(i => 
  i.phone && 
  !i.message_template && 
  !i.nome_evento
);

// --- Helpers ---

function normalizePhone(phone) {
  if (!phone) return null;
  let digits = phone.replace(/\D/g, '');
  if (digits.length >= 10 && digits.length <= 11) {
    digits = '55' + digits;
  }
  return digits;
}

function normalizeText(text) {
  if (!text) return '';
  return text.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

function formatDate(isoDate) {
  if (!isoDate) return '';
  return new Date(isoDate).toLocaleDateString('pt-BR', { timeZone: 'America/Sao_Paulo' });
}

function formatTime(isoDate) {
  if (!isoDate) return '';
  return new Date(isoDate).toLocaleTimeString('pt-BR', {
    hour: '2-digit',
    minute: '2-digit',
    timeZone: 'America/Sao_Paulo'
  });
}

function getAddress(event) {
    if (event.tipo_local === 'online' && event.link_online) {
        return event.link_online;
    }
    return event.endereco_completo || event.local_evento || (event.cidade ? `${event.cidade}-${event.estado}` : '');
}

function resolveVariable(variableName, participant, event) {
  const name = normalizeText(variableName);

  const systemMap = {
    // --- EVENTO ---
    'nome_evento': event?.nome_evento,
    'evento': event?.nome_evento,
    'data_evento': formatDate(event?.data_hora_inicio),
    'data': formatDate(event?.data_hora_inicio),
    'hora_evento': formatTime(event?.data_hora_inicio),
    'hora': formatTime(event?.data_hora_inicio),
    'data_final': formatDate(event?.data_hora_fim),
    'data_fim': formatDate(event?.data_hora_fim),
    'hora_final': formatTime(event?.data_hora_fim),
    'hora_fim': formatTime(event?.data_hora_fim),
    'local_evento': event?.local_evento,
    'endereco': getAddress(event),
    'link_online': event?.link_online,
    'organizador': event?.organizador,
    'categoria': event?.categoria,
    'descricao': event?.descricao,

    // --- PARTICIPANTE ---
    'nome_participante': participant.name,
    'nome': participant.name,
    'telefone_participante': participant.phone,
    'telefone': participant.phone
  };

  if (systemMap[name] !== undefined) return systemMap[name];

  if (name.includes('nome') && name.includes('participante')) return participant.name;
  if (name.includes('nome') && name.includes('evento')) return event?.nome_evento;
  if (name.includes('data')) return formatDate(event?.data_hora_inicio);
  if (name.includes('hora')) return formatTime(event?.data_hora_inicio);
  if (name.includes('organizador')) return event?.organizador;

  return '';
}

// NOVO HELPER: Define se é video, imagem ou texto
function getMediaInfo(template, event) {
    // 0. Se o TEMPLATE NÃO tem header, acabou.
    const templateHasHeader =
        template.mapping_header_image_url ||
        template.mapping_header_video_url ||
        template.template_header_image_url ||
        template.template_header_video_url;

    if (!templateHasHeader) {
        return {
            type: 'text',
            url: null
        };
    }

    // 1. Header VÍDEO (somente se template permitir)
    const videoUrl =
        template.mapping_header_video_url ||
        template.template_header_video_url;

    if (videoUrl) {
        return {
            type: 'video',
            url: videoUrl
        };
    }

    // 2. Header IMAGEM (somente se template permitir)
    const imageUrl =
        template.mapping_header_image_url ||
        template.template_header_image_url;

    if (imageUrl) {
        return {
            type: 'image',
            url: imageUrl
        };
    }

    // 3. Template tem header, mas sem mídia configurada
    return {
        type: 'text',
        url: null
    };
}


// --- Montagem Final ---

return participants.map(participant => {
  const parameters = (template.variables || []).map(variableName => 
    resolveVariable(variableName, participant, event)
  );

  // Calcula a mídia para esta mensagem
  const mediaInfo = getMediaInfo(template, event);

  return {
    json: {
      participant_id: participant.id,
      event_id: participant.event_id || event?.id,

      phone: normalizePhone(participant.phone),

      message_template: template.message_template,
      meta_template_name: template.meta_template_name,

      parameters: parameters, 

      // NOVOS CAMPOS DINÂMICOS
      media_type: mediaInfo.type, // 'video', 'image' ou 'text'
      media_url: mediaInfo.url,   // URL ou null

      // Mantivemos requires_image como fallback legacy, mas agora baseado na detecção real
      requires_image: mediaInfo.type === 'image',

      status: participant.status
    }
  };
});

